import {
  BrowserRouter,
  Routes,
  Route,
  Link
} from "react-router-dom";

import Login from "./pages/Login";
import Signup from "./pages/Signup";
import Dashboard from "./pages/Dashboard";
import AddEmployee from "./pages/AddEmployee";
import EmployeeList from "./pages/EmployeeList";
import SearchEmployee from "./pages/SearchEmployee";
import EditEmployee from "./pages/EditEmployee";
import AddFeedback from "./pages/AddFeedback";
import EmployeeProfile from "./pages/EmployeeProfile";

import ProtectedRoute from "./components/ProtectedRoute";

function App() {

  const token = localStorage.getItem("token");

  return (

    <BrowserRouter>

      <div
        style={{
          padding: "20px",
          display: "flex",
          gap: "20px",
          flexWrap: "wrap"
        }}
      >

        {!token && (

          <>
            <Link to="/">
              Login
            </Link>

            <Link to="/signup">
              Signup
            </Link>
          </>

        )}

        {token && (

          <>
            <Link to="/dashboard">
              Dashboard
            </Link>

            <Link to="/add-employee">
              Add Employee
            </Link>

            <Link to="/employees">
              Employee List
            </Link>

            <Link to="/search">
              Search Employee
            </Link>

            <Link to="/add-feedback">
              Add Feedback
            </Link>
          </>

        )}

      </div>

      <Routes>

        <Route
          path="/"
          element={<Login />}
        />

        <Route
          path="/signup"
          element={<Signup />}
        />

        <Route
          path="/dashboard"
          element={
            <ProtectedRoute>
              <Dashboard />
            </ProtectedRoute>
          }
        />

        <Route
          path="/add-employee"
          element={
            <ProtectedRoute>
              <AddEmployee />
            </ProtectedRoute>
          }
        />

        <Route
          path="/employees"
          element={
            <ProtectedRoute>
              <EmployeeList />
            </ProtectedRoute>
          }
        />

        <Route
          path="/search"
          element={
            <ProtectedRoute>
              <SearchEmployee />
            </ProtectedRoute>
          }
        />

        <Route
          path="/edit/:id"
          element={
            <ProtectedRoute>
              <EditEmployee />
            </ProtectedRoute>
          }
        />

        <Route
          path="/profile/:id"
          element={
            <ProtectedRoute>
              <EmployeeProfile />
            </ProtectedRoute>
          }
        />

        <Route
          path="/add-feedback"
          element={
            <ProtectedRoute>
              <AddFeedback />
            </ProtectedRoute>
          }
        />

      </Routes>

    </BrowserRouter>

  );

}

export default App;
